changeSet.sql:
CREATE TABLE iam_user_attributes ( id VARCHAR(36) PRIMARY KEY REFERENCES user_entity(id), expiry_date TIMESTAMP WITHOUT TIME ZONE NOT NULL, inactivity_notification_sent BOOLEAN DEFAULT false, expired_notification_sent BOOLEAN DEFAULT false );
CREATE TABLE iam_mail_list ( id SERIAL PRIMARY KEY, name VARCHAR NOT NULL, UNIQUE(name) );
CREATE TABLE iam_mail_list_user ( mail_list_id INTEGER REFERENCES iam_mail_list(id) ON DELETE CASCADE, user_id VARCHAR(36) REFERENCES user_entity(id), PRIMARY KEY (mail_list_id, user_id) );
CREATE TABLE iam_mail_type ( id INTEGER PRIMARY KEY, name VARCHAR NOT NULL );
CREATE TABLE iam_mail ( id SERIAL PRIMARY KEY, send_date TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now(), expiry_date TIMESTAMP WITH TIME ZONE, sender VARCHAR NOT NULL, text VARCHAR NOT NULL, subject VARCHAR NOT NULL, archived BOOLEAN NOT NULL, type INTEGER NOT NULL REFERENCES iam_mail_type(id), recipient INTEGER NOT NULL REFERENCES iam_mail_list(id), user_id VARCHAR(36) NOT NULL REFERENCES iam_user_attributes(id) );
CREATE TABLE iam_institution_category ( name VARCHAR PRIMARY KEY );
CREATE TABLE iam_institution ( id SERIAL PRIMARY KEY, name VARCHAR NOT NULL UNIQUE, short_name VARCHAR NOT NULL UNIQUE, service_building_street VARCHAR NOT NULL, service_building_postal_code VARCHAR NOT NULL, service_building_location VARCHAR NOT NULL, address_street VARCHAR, address_postal_code VARCHAR, address_location VARCHAR, central_phone VARCHAR NOT NULL, central_fax VARCHAR, central_mail VARCHAR NOT NULL, imis_id VARCHAR, imis_usergroup_id VARCHAR(3) NOT NULL, x_coordinate FLOAT, y_coordinate FLOAT, active BOOLEAN DEFAULT true );
CREATE TABLE iam_institution_categories ( institution_id INTEGER REFERENCES iam_institution(id), category_name VARCHAR REFERENCES iam_institution_category, PRIMARY KEY (institution_id, category_name) );
CREATE TABLE iam_institution_user ( institution_id INTEGER REFERENCES iam_institution(id) ON DELETE CASCADE, user_id VARCHAR(36) REFERENCES iam_user_attributes(id), PRIMARY KEY(institution_id, user_id) );
CREATE TABLE iam_event ( id SERIAL PRIMARY KEY, start_date TIMESTAMP WITH TIME ZONE NOT NULL, end_date TIMESTAMP WITH TIME ZONE NOT NULL, title VARCHAR NOT NULL, site VARCHAR NOT NULL, description VARCHAR NOT NULL );

ALTER TABLE iam_institution_user
    DROP CONSTRAINT iam_institution_user_is_primary_institution_check,
    DROP CONSTRAINT iam_institution_user_user_id_is_primary_institution_key;
UPDATE iam_institution_user SET is_primary_institution = false
    WHERE is_primary_institution IS NULL;
ALTER TABLE iam_institution_user
    ALTER COLUMN is_primary_institution SET DEFAULT FALSE,
    ALTER COLUMN is_primary_institution SET NOT NULL;
CREATE UNIQUE INDEX one_primary_institution
    ON iam_institution_user (user_id, institution_id)
    WHERE is_primary_institution = true;

DROP INDEX one_primary_institution;
ALTER TABLE iam_institution_user
    DROP COLUMN is_primary_institution;

CREATE TABLE iam_institution_central_alarm_mail_addresses (
    institution_id INTEGER REFERENCES iam_institution,
    mail VARCHAR,
    PRIMARY KEY(institution_id, mail)
);

CREATE TABLE iam_institution_central_alarm_phone_numbers (
    institution_id INTEGER REFERENCES iam_institution,
    phone VARCHAR,
    PRIMARY KEY(institution_id, phone)
);

ALTER TABLE iam_institution_category
    RENAME TO iam_institution_tag;
ALTER TABLE iam_institution_categories
    RENAME TO iam_institution_tags;
ALTER TABLE iam_institution_tags
    RENAME category_name TO tag_name;

ALTER TABLE iam_institution
    RENAME short_name TO meas_facil_name;
ALTER TABLE iam_institution
    RENAME imis_id TO meas_facil_id;

ALTER TABLE iam_institution
    ALTER COLUMN meas_facil_id TYPE VARCHAR(7),
    ADD CONSTRAINT meas_facil_id_length CHECK (
        char_length(meas_facil_id) >= 5
    );

ALTER TABLE iam_institution
    ALTER COLUMN central_mail DROP NOT NULL,
    ALTER COLUMN central_phone DROP NOT NULL;

ALTER TABLE iam_mail
    DROP COLUMN recipient;
DROP TABLE iam_mail_list_user;
DROP TABLE iam_mail_list;

UPDATE iam_institution SET active = false WHERE active IS NULL;
ALTER TABLE iam_institution
    ALTER COLUMN active SET DEFAULT false,
    ALTER COLUMN active SET NOT NULL;

CREATE TABLE iam_institution_operation_mode_change_sms_phone_numbers (
    institution_id INTEGER REFERENCES iam_institution,
    phone VARCHAR,
    PRIMARY KEY(institution_id, phone)
);
ALTER TABLE iam_institution_central_alarm_mail_addresses
    RENAME TO iam_institution_operation_mode_change_mail_addresses;
ALTER TABLE iam_institution_central_alarm_phone_numbers
    RENAME TO iam_institution_operation_mode_change_phone_numbers;

CREATE TABLE iam_institution_mail (
    institution_id INTEGER REFERENCES iam_institution,
    mail VARCHAR NOT NULL,
    PRIMARY KEY(institution_id, mail)
);
CREATE TABLE iam_institution_phone (
    institution_id INTEGER REFERENCES iam_institution,
    phone VARCHAR NOT NULL,
    PRIMARY KEY(institution_id, phone)
);

INSERT INTO iam_institution_mail (institution_id, mail)
    SELECT id, central_mail FROM iam_institution WHERE central_mail IS NOT NULL;

INSERT INTO iam_institution_phone (institution_id, phone)
    SELECT id, central_phone FROM iam_institution WHERE central_phone IS NOT NULL;

ALTER TABLE iam_institution DROP COLUMN central_mail;
ALTER TABLE iam_institution DROP COLUMN central_phone;

ALTER TABLE iam_institution_user
  DROP CONSTRAINT iam_institution_user_institution_id_fkey;
ALTER TABLE iam_institution_user
  ADD FOREIGN KEY (institution_id) REFERENCES keycloak.iam_institution;

CREATE TABLE iam_network (
  name VARCHAR PRIMARY KEY
);
INSERT INTO iam_network VALUES ('19');
ALTER TABLE iam_institution
  ADD COLUMN network VARCHAR REFERENCES iam_network(name);
UPDATE iam_institution SET network = '19';
ALTER TABLE iam_institution
  ALTER COLUMN network SET NOT NULL;
ALTER TABLE iam_user_attributes
  ADD COLUMN network VARCHAR REFERENCES iam_network(name);
UPDATE iam_user_attributes SET network = '19';
ALTER TABLE iam_user_attributes
  ALTER COLUMN network SET NOT NULL;

CREATE TABLE iam_mail_user (
    mail_id INTEGER REFERENCES iam_mail(id) ON DELETE CASCADE,
    recipient VARCHAR(36) REFERENCES user_entity(id),
    PRIMARY KEY (mail_id, recipient)
);
